    },
    404: {
      description: "Doctor not found",
      content: { "application/json": { schema: errorResponse } },
    },
    409: {
      description: "Slot conflict — already booked",
      content: { "application/json": { schema: errorResponse } },
    },
    500: {
      description: "Internal server error",
      content: { "application/json": { schema: errorResponse } },
    },
