    const body = await res.json();
    expect(body.message).toMatch(/eligible/i);
  });

  it("returns 409 when prescription already exists for this medical record", async () => {
    vi.mocked(db.select)
      .mockReturnValueOnce(makeSimpleSelectChain([mockDoctor]) as any)
      .mockReturnValueOnce(
