      headers: { ...jsonHeaders, ...bearer(doctorToken) },
      body: JSON.stringify({
        medicalRecordId: "not-a-uuid",
        items: validBody.items,
      }),
    });
    expect(res.status).toBe(400);
  });
});

// ─── PUT /prescriptions/:id ─────────────────────────────────────────────────

describe("PUT /prescriptions/:id", () => {
