    });
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.notes).toBe("Updated notes");
  });

  it("returns 400 when items array is empty", async () => {
    const res = await app.request(`${BASE_URL}/${PRESCRIPTION_ID}`, {
